mapper.select:
SELECT FROM alevel_question_material_ref WHERE alevel_question_id IN
#{questionId}
AND status = 1 AND delete_flag = '1' ORDER BY alevel_question_id ASC, sort_order ASC, alevel_question_material_ref_id ASC

mapper.update:
UPDATE alevel_question_material_ref
SET status = 0,
    update_time = #{updateTime}
WHERE alevel_question_material_ref_id = #{materialRefId}
  AND status = 1
  AND delete_flag = '1'

UPDATE alevel_question_material_ref
SET status = 0,
    update_time = #{updateTime}
WHERE alevel_question_id = #{questionId}
  AND status = 1
  AND delete_flag = '1'

UPDATE alevel_question_material_ref
SET status = 0,
    update_time = #{updateTime}
WHERE alevel_question_id IN (
    SELECT alevel_question_id
    FROM alevel_question
    WHERE alevel_paper_id = #{paperId}
)
  AND status = 1
  AND delete_flag = '1'
